#include <fstream>
#include <string>
#include <iostream>
#include <cstdio> // For std::remove

class Logger {
public:
    Logger(const std::string& filename) : logFilename(filename) {
        outFile.open(logFilename, std::ios::app);
        if (!outFile.is_open()) {
            std::cerr << "Error: Could not open log file " << logFilename << std::endl;
        }
    }

    ~Logger() {
        if (outFile.is_open()) {
            outFile.close();
        }
    }

    void logMessage(const std::string& message) {
        if (outFile.is_open()) {
            outFile << message << std::endl;
        } else {
            std::cerr << "Error: Log file is not open. Message not logged." << std::endl;
        }
    }

private:
    std::ofstream outFile;
    std::string logFilename;
};

int main() {
    std::string valid_file = "test_log_2832_valid.txt";
    std::string invalid_file = "/nonexistent_dir/test_log_2832_invalid.txt"; 

    std::remove(valid_file.c_str());
    std::remove(invalid_file.c_str());

    // Test 1: Valid file path
    Logger validLogger(valid_file);
    validLogger.logMessage("First message.");
    validLogger.logMessage("Second message.");

    std::cout << "--- Content of valid_file: ---\n";
    std::ifstream validInFile(valid_file);
    if (validInFile.is_open()) {
        std::string line;
        while (std::getline(validInFile, line)) {
            std::cout << line << "\n";
        }
        validInFile.close();
    } else {
        std::cout << "Valid log file could not be opened for reading.\n";
    }
    std::remove(valid_file.c_str());

    // Test 2: Invalid file path
    Logger invalidLogger(invalid_file); 
    invalidLogger.logMessage("This should not be logged.");

    std::cout << "--- Content of invalid_file (if any): ---\n";
    std::ifstream invalidInFile(invalid_file);
    if (invalidInFile.is_open()) {
        std::string line;
        bool content_found = false;
        while (std::getline(invalidInFile, line)) {
            std::cout << line << "\n";
            content_found = true;
        }
        invalidInFile.close();
        if (!content_found) {
             std::cout << "Invalid log file was created but is empty.\n";
        }
    } else {
        std::cout << "Invalid log file was not created or could not be opened for reading.\n";
    }
    std::remove(invalid_file.c_str());

    return 0;
}
